   300→<body>
   301→    <!-- Header -->
   302→    <div class="header">
   303→        <div class="header-left">
   304→            <span class="hamburger">&#9776;</span>
   305→            <span class="title">Interactive Canvas - Semantic Zoom</span>
   306→        </div>
   307→        <div class="header-right">
   308→            <div class="zoom-display">
   309→                <span>Zoom:</span>
   310→                <span id="zoom-value" class="zoom-value">1.00x</span>
   311→            </div>
   312→            <div class="lod-display">
   313→                <span>LOD:</span>
   314→                <span id="lod-badge" class="lod-badge">MESO</span>
   315→            </div>
   316→            <button id="reset-btn" class="reset-btn">Reset View</button>
   317→        </div>
   318→    </div>
   319→
   320→    <!-- Main Container -->
   321→    <div class="main-container">
   322→        <!-- Sidebar -->
   323→        <div class="sidebar">
   324→            <div class="sidebar-header">ID</div>
   325→            <div id="sidebar-content" class="sidebar-content"></div>
   326→        </div>
   327→
   328→        <!-- Canvas Container -->
   329→        <div class="canvas-container">
   330→            <!-- Timeline Header -->
   331→            <div id="timeline-header" class="timeline-header"></div>
   332→
   333→            <!-- deck.gl Canvas -->
   334→            <canvas id="deck-canvas"></canvas>
   335→
   336→            <!-- Instructions -->
   337→            <div id="instructions" class="instructions">
   338→                Scroll to zoom &bull; Drag to pan &bull; Double-click to zoom in
   339→            </div>
   340→
   341→            <!-- Legend -->
   342→            <div class="legend">
   343→                <div class="legend-title">Zoom Levels (LOD)</div>
   344→                <div class="legend-item">
   345→                    <div class="legend-color" style="background: #facc15;"></div>
   346→                    <span class="legend-label">Macro (&lt;0.5x) - Heatmap</span>
   347→                </div>
   348→                <div class="legend-item">
   349→                    <div class="legend-color" style="background: #3b82f6;"></div>
   350→                    <span class="legend-label">Meso (0.5-2x) - DNA Strips</span>
   351→                </div>
   352→                <div class="legend-item">
   353→                    <div class="legend-color" style="background: #22c55e;"></div>
   354→                    <span class="legend-label">Micro (&gt;2x) - Task Cards</span>
   355→                </div>
   356→            </div>
   357→
   358→            <!-- Zoom Controls -->
   359→            <div class="zoom-controls">
   360→                <button id="zoom-in-btn" class="zoom-btn">+</button>
   361→                <div class="zoom-divider"></div>
   362→                <button id="zoom-out-btn" class="zoom-btn">&minus;</button>
   363→            </div>
   364→        </div>
