   367→    <script>
   368→        // ============================================
   369→        // CONFIGURATION
   370→        // ============================================
   371→        const CONFIG = {
   372→            HEADER_HEIGHT: 48,
   373→            TIMELINE_HEIGHT: 32,
   374→            SIDEBAR_WIDTH: 56,
   375→            ROW_HEIGHT: 25,
   376→            DAY_WIDTH: 10,
   377→            START_DATE: new Date(2024, 0, 1),
   378→            TRAINS: 50,
   379→            VISIBLE_DAYS: 150,
   380→            MIN_ZOOM: -2,
   381→            MAX_ZOOM: 4,
   382→            ZOOM_SENSITIVITY: 0.003,
   383→            LOD_THRESHOLDS: {
   384→                MACRO: 0.5,
   385→                MICRO: 2.0
   386→            }
   387→        };
   388→
   389→        const COLORS = {
   390→            gray: [156, 163, 175, 230],
   391→            blue: [59, 130, 246, 230],
   392→            orange: [245, 158, 11, 230],
   393→            conflict: [239, 68, 68, 255],
   394→            rowEven: [255, 255, 255, 255],
   395→            rowOdd: [249, 250, 251, 255]
   396→        };
   397→
   398→        // ============================================
   399→        // STATE
   400→        // ============================================
   401→        const state = {
   402→            viewState: {
   403→                target: [750, 350, 0],
   404→                zoom: 0,
   405→                minZoom: CONFIG.MIN_ZOOM,
   406→                maxZoom: CONFIG.MAX_ZOOM
   407→            },
   408→            tasks: [],
   409→            trains: [],
   410→            deckInstance: null,
   411→            initialTarget: null
   412→        };
   413→
   414→        // ============================================
   415→        // DATA GENERATION
   416→        // ============================================
   417→        function generateData() {
   418→            // Generate trains
   419→            state.trains = Array.from({ length: CONFIG.TRAINS }, (_, i) => ({
   420→                id: `T${String(i + 1).padStart(3, '0')}`,
   421→                index: i
   422→            }));
   423→
   424→            // Generate tasks matching the image pattern
   425→            state.tasks = [];
   426→            const seededRandom = createSeededRandom(42);
   427→
   428→            state.trains.forEach((train, trainIndex) => {
   429→                // Generate 3-8 tasks per train
   430→                const taskCount = 3 + Math.floor(seededRandom() * 6);
   431→
   432→                for (let t = 0; t < taskCount; t++) {
   433→                    const startDay = Math.floor(seededRandom() * 140);
   434→                    const duration = 3 + Math.floor(seededRandom() * 12);
   435→
   436→                    // Random type distribution matching the image
   437→                    const typeRoll = seededRandom();
   438→                    let type, color;
   439→                    if (typeRoll < 0.35) {
   440→                        type = 'inspection';
   441→                        color = 'gray';
   442→                    } else if (typeRoll < 0.70) {
   443→                        type = 'maintenance';
   444→                        color = 'blue';
   445→                    } else {
   446→                        type = 'corrective';
   447→                        color = 'orange';
   448→                    }
   449→
   450→                    // Some tasks have conflicts (5%)
   451→                    const hasConflict = seededRandom() < 0.05;
   452→
   453→                    state.tasks.push({
   454→                        id: `${train.id}-${t}`,
   455→                        trainId: train.id,
   456→                        trainIndex,
   457→                        startDay,
   458→                        duration,
   459→                        type,
   460→                        color,
   461→                        hasConflict
   462→                    });
   463→                }
   464→            });
   465→        }
   466→
   467→        function createSeededRandom(seed) {
   468→            return function() {
   469→                seed = (seed * 1103515245 + 12345) & 0x7fffffff;
   470→                return seed / 0x7fffffff;
   471→            };
   472→        }
   473→
   474→        // ============================================
   475→        // DECK.GL SETUP
   476→        // ============================================
   477→        function initDeck() {
   478→            const canvas = document.getElementById('deck-canvas');
   479→            const container = canvas.parentElement;
   480→
   481→            canvas.width = container.clientWidth;
   482→            canvas.height = container.clientHeight - CONFIG.TIMELINE_HEIGHT;
   483→
   484→            // Calculate initial target to show T001 at top and Jan 1 at left
   485→            const initialX = canvas.width / 2;
   486→            const initialY = canvas.height / 2;
   487→            state.viewState.target = [initialX, initialY, 0];
   488→            state.initialTarget = [initialX, initialY, 0];
   489→
   490→            state.deckInstance = new deck.Deck({
   491→                canvas: canvas,
   492→                width: canvas.width,
   493→                height: canvas.height,
   494→                views: [
   495→                    new deck.OrthographicView({
   496→                        id: 'main',
   497→                        flipY: false
   498→                    })
   499→                ],
   500→                initialViewState: state.viewState,
   501→                controller: {
   502→                    type: deck.OrthographicController,
   503→                    scrollZoom: true,
   504→                    dragPan: true,
   505→                    doubleClickZoom: true,
   506→                    minZoom: CONFIG.MIN_ZOOM,
   507→                    maxZoom: CONFIG.MAX_ZOOM
   508→                },
   509→                onViewStateChange: ({ viewState }) => {
   510→                    state.viewState = viewState;
   511→                    updateUI();
   512→                    renderLayers();
   513→                },
   514→                layers: []
   515→            });
   516→
   517→            renderLayers();
   518→            updateUI();
   519→        }
   520→
   521→        // ============================================
   522→        // RENDER LAYERS
   523→        // ============================================
   524→        function renderLayers() {
   525→            const zoom = Math.pow(2, state.viewState.zoom);
   526→            const dayWidth = CONFIG.DAY_WIDTH * zoom;
   527→            const rowHeight = CONFIG.ROW_HEIGHT;
   528→
   529→            // Row backgrounds
   530→            const rowBackgrounds = state.trains.map((train, i) => ({
   531→                polygon: [
   532→                    [0, i * rowHeight],
   533→                    [CONFIG.VISIBLE_DAYS * CONFIG.DAY_WIDTH, i * rowHeight],
   534→                    [CONFIG.VISIBLE_DAYS * CONFIG.DAY_WIDTH, (i + 1) * rowHeight],
   535→                    [0, (i + 1) * rowHeight]
   536→                ],
   537→                color: i % 2 === 0 ? COLORS.rowEven : COLORS.rowOdd
   538→            }));
   539→
   540→            // Task rectangles
   541→            const taskRects = state.tasks.map(task => {
   542→                const x = task.startDay * CONFIG.DAY_WIDTH;
   543→                const y = task.trainIndex * rowHeight + 2;
   544→                const width = task.duration * CONFIG.DAY_WIDTH;
   545→                const height = rowHeight - 4;
   546→
   547→                return {
   548→                    polygon: [
   549→                        [x, y],
   550→                        [x + width, y],
   551→                        [x + width, y + height],
   552→                        [x, y + height]
   553→                    ],
   554→                    color: COLORS[task.color],
   555→                    hasConflict: task.hasConflict
   556→                };
   557→            });
   558→
   559→            // Conflict borders
   560→            const conflictTasks = state.tasks.filter(t => t.hasConflict).map(task => {
   561→                const x = task.startDay * CONFIG.DAY_WIDTH;
   562→                const y = task.trainIndex * rowHeight + 2;
   563→                const width = task.duration * CONFIG.DAY_WIDTH;
   564→                const height = rowHeight - 4;
   565→
   566→                return {
   567→                    polygon: [
   568→                        [x, y],
   569→                        [x + width, y],
   570→                        [x + width, y + height],
   571→                        [x, y + height]
   572→                    ]
   573→                };
   574→            });
   575→
   576→            const layers = [
   577→                // Row backgrounds
   578→                new deck.PolygonLayer({
   579→                    id: 'row-backgrounds',
   580→                    data: rowBackgrounds,
   581→                    getPolygon: d => d.polygon,
   582→                    getFillColor: d => d.color,
   583→                    stroked: false,
   584→                    filled: true
   585→                }),
   586→                // Task blocks
   587→                new deck.PolygonLayer({
   588→                    id: 'task-blocks',
   589→                    data: taskRects,
   590→                    getPolygon: d => d.polygon,
   591→                    getFillColor: d => d.color,
   592→                    stroked: false,
   593→                    filled: true,
   594→                    pickable: true
   595→                }),
   596→                // Conflict borders
   597→                new deck.PolygonLayer({
   598→                    id: 'conflict-borders',
   599→                    data: conflictTasks,
   600→                    getPolygon: d => d.polygon,
   601→                    getFillColor: [0, 0, 0, 0],
   602→                    getLineColor: COLORS.conflict,
   603→                    getLineWidth: 2,
   604→                    stroked: true,
   605→                    filled: false,
   606→                    lineWidthUnits: 'pixels'
   607→                })
   608→            ];
   609→
   610→            state.deckInstance.setProps({ layers });
   611→        }
   612→
   613→        // ============================================
   614→        // UI UPDATES
   615→        // ============================================
   616→        function updateUI() {
   617→            const zoom = Math.pow(2, state.viewState.zoom);
   618→
   619→            // Update zoom display
   620→            document.getElementById('zoom-value').textContent = zoom.toFixed(2) + 'x';
   621→
   622→            // Update LOD badge
   623→            const lodBadge = document.getElementById('lod-badge');
   624→            let lod = 'MESO';
   625→            lodBadge.className = 'lod-badge';
   626→
   627→            if (zoom < CONFIG.LOD_THRESHOLDS.MACRO) {
   628→                lod = 'MACRO';
   629→                lodBadge.classList.add('macro');
   630→            } else if (zoom > CONFIG.LOD_THRESHOLDS.MICRO) {
   631→                lod = 'MICRO';
   632→                lodBadge.classList.add('micro');
   633→            }
   634→            lodBadge.textContent = lod;
   635→
   636→            // Update timeline header
   637→            renderTimeline();
   638→
   639→            // Update sidebar
   640→            renderSidebar();
   641→        }
   642→
   643→        function renderTimeline() {
   644→            const container = document.getElementById('timeline-header');
   645→            const canvas = document.getElementById('deck-canvas');
   646→            const zoom = Math.pow(2, state.viewState.zoom);
   647→            const viewportWidth = canvas.width;
   648→
   649→            // Calculate world coordinates visible on canvas
   650→            const targetX = state.viewState.target[0];
   651→            const worldLeft = (targetX - viewportWidth / 2) / zoom;
   652→            const worldRight = (targetX + viewportWidth / 2) / zoom;
   653→
   654→            // Convert world X to days
   655→            const startDay = Math.floor(worldLeft / CONFIG.DAY_WIDTH);
   656→            const endDay = Math.ceil(worldRight / CONFIG.DAY_WIDTH);
   657→
   658→            // Determine interval based on zoom
   659→            let interval = 7; // Weekly by default
   660→            if (zoom < 0.3) interval = 30;
   661→            else if (zoom < 0.5) interval = 14;
   662→            else if (zoom > 2) interval = 1;
   663→
   664→            let html = '';
   665→            const baseDate = new Date(CONFIG.START_DATE);
   666→
   667→            for (let day = Math.max(0, Math.floor(startDay / interval) * interval);
   668→                 day <= Math.min(CONFIG.VISIBLE_DAYS, endDay + interval);
   669→                 day += interval) {
   670→                const date = new Date(baseDate);
   671→                date.setDate(date.getDate() + day);
   672→
   673→                // Calculate screen position
   674→                const worldX = day * CONFIG.DAY_WIDTH;
   675→                const screenX = (worldX - worldLeft) * zoom;
   676→
   677→                if (screenX >= -100 && screenX < viewportWidth + 100) {
   678→                    const format = date.toLocaleDateString('en', { month: 'short', day: 'numeric' });
   679→                    html += `<div class="date-label" style="left: ${screenX}px">${format}</div>`;
   680→                }
   681→            }
   682→
   683→            container.innerHTML = html;
   684→        }
   685→
   686→        function renderSidebar() {
   687→            const container = document.getElementById('sidebar-content');
   688→            const zoom = Math.pow(2, state.viewState.zoom);
   689→            const rowHeight = CONFIG.ROW_HEIGHT;
   690→            const canvas = document.getElementById('deck-canvas');
   691→            const canvasHeight = canvas.height;
   692→
   693→            // Calculate world coordinates visible on canvas
   694→            const targetY = state.viewState.target[1];
   695→            const worldTop = (targetY - canvasHeight / 2) / zoom;
   696→            const worldBottom = (targetY + canvasHeight / 2) / zoom;
   697→
   698→            // Calculate which train rows are visible
   699→            const startIndex = Math.max(0, Math.floor(worldTop / rowHeight));
   700→            const endIndex = Math.min(CONFIG.TRAINS, Math.ceil(worldBottom / rowHeight) + 1);
   701→
   702→            let html = '';
   703→            for (let i = startIndex; i < endIndex; i++) {
   704→                html += `<div class="train-row" style="height: ${rowHeight}px">T${String(i + 1).padStart(3, '0')}</div>`;
   705→            }
   706→
   707→            container.innerHTML = html;
   708→        }
