   753→            }, 5000);
   754→
   755→            // Window resize
   756→            window.addEventListener('resize', () => {
   757→                const canvas = document.getElementById('deck-canvas');
   758→                const container = canvas.parentElement;
   759→                canvas.width = container.clientWidth;
   760→                canvas.height = container.clientHeight - CONFIG.TIMELINE_HEIGHT;
   761→
   762→                state.deckInstance.setProps({
   763→                    width: canvas.width,
   764→                    height: canvas.height
   765→                });
   766→
   767→                updateUI();
   768→            });
   769→        }
